using System.Text.Json;

namespace Azure.ResourceManager
{
    internal static class ResponseErrorHelper
    {
        public static void Write(Utf8JsonWriter writer, ResponseError error)
        {
            if (error == null)
            {
                writer.WriteNullValue();
                return;
            }
            writer.WriteStartObject();
            if (error.Code != null)
            {
                writer.WriteString("code"u8, error.Code);
            }
            if (error.Message != null)
            {
                writer.WriteString("message"u8, error.Message);
            }
            writer.WriteEndObject();
        }

        public static ResponseError Deserialize(string json)
        {
            using var document = JsonDocument.Parse(json);
            var element = document.RootElement;
            if (element.ValueKind == JsonValueKind.Null)
            {
                return null;
            }
            string code = null;
            string message = null;
            if (element.TryGetProperty("code"u8, out var codeValue))
            {
                code = codeValue.GetString();
            }
            if (element.TryGetProperty("message"u8, out var messageValue))
            {
                message = messageValue.GetString();
            }
            return new ResponseError(code, message);
        }
    }
}

